import { Component, Host, Prop, State, h } from '@stencil/core';
import type { IProperty } from '@/models/property';
import { CityLedgerService, type CLStatements } from '@/services/city-ledger';
import { PropertyService } from '@/services/property.service';
import { formatAmount } from '@/utils/utils';
import Token from '@/models/Token';
import moment from 'moment';

const DATE_DISPLAY = 'MMM DD, YYYY';

@Component({
  tag: 'ir-cl-statement-preview',
  styleUrl: 'ir-cl-statement-preview.css',
  shadow: true,
})
export class IrClStatementPreview {
  @Prop() propertyId: number;
  @Prop() ticket: string;
  @Prop() baseurl: string;
  @Prop() agentId: number;
  @Prop() agentName: string;
  @Prop() fromDate: string;
  @Prop() toDate: string;
  @Prop() currencyId: number;

  @State() private isLoading = false;
  @State() private error: string | null = null;
  @State() private property: IProperty | null = null;
  @State() private statement: CLStatements | null = null;

  private tokenService = new Token();
  private propertyService = new PropertyService();
  private cityLedgerService = new CityLedgerService();

  componentWillLoad() {
    if (!this.ticket) {
      this.error = 'Authentication ticket is required.';
      return;
    }
    if (this.baseurl) this.tokenService.setBaseUrl(this.baseurl);
    this.tokenService.setToken(this.ticket);
    return this.fetchData();
  }

  private async fetchData() {
    this.isLoading = true;
    this.error = null;
    try {
      const [propertyData, statement] = await Promise.all([
        this.propertyService.getExposedProperty({ id: this.propertyId, language: 'en' }),
        this.cityLedgerService.getCLStatement({
          AGENCY_ID: this.agentId,
          CURRENCY_ID: this.currencyId,
          START_DATE: this.fromDate,
          END_DATE: this.toDate,
        }),
      ]);
      this.property = propertyData?.My_Result ?? null;
      this.statement = statement;
    } catch (e: any) {
      this.error = e?.message ?? 'Failed to load statement data.';
    } finally {
      this.isLoading = false;
    }
  }

  render() {
    if (!this.ticket) {
      return (
        <Host>
          <div class="document-state document-state--error">Authentication ticket is required.</div>
        </Host>
      );
    }
    if (this.isLoading) {
      return (
        <Host>
          <div class="document-state">
            <ir-spinner></ir-spinner>
          </div>
        </Host>
      );
    }
    if (this.error) {
      return (
        <Host>
          <div class="document-state document-state--error">{this.error}</div>
        </Host>
      );
    }
    if (!this.statement) {
      return (
        <Host>
          <div class="document-state document-state--error">No statement data found.</div>
        </Host>
      );
    }

    const { STARTING_BALANCE, ENDING_BALANCE, My_Rows } = this.statement;
    const currency = this.property?.currency?.symbol ?? '$';
    const fmt = (v: number | null | undefined) => (v != null ? formatAmount(currency, v) : '—');

    return (
      <Host>
        <div class="document">
          <ir-cl-document-header style={{ marginBottom: '1.75rem' }} property={this.property as any} agentName={this.agentName} documentType="statement"></ir-cl-document-header>

          <table class="stmt-table">
            <thead>
              <tr>
                <th class="stmt-th stmt-th--date">Date</th>
                <th class="stmt-th">Description</th>
                <th class="stmt-th">Document #</th>
                <th class="stmt-th stmt-th--num">Debit</th>
                <th class="stmt-th stmt-th--num">Credit</th>
                <th class="stmt-th stmt-th--num">Balance</th>
              </tr>
            </thead>
            <tbody>
              {/* Opening balance */}
              <tr class="stmt-row stmt-row--balance">
                <td class="stmt-td" colSpan={3}>
                  Opening Balance — {moment(this.fromDate).format(DATE_DISPLAY)}
                </td>
                <td class="stmt-td"></td>
                <td class="stmt-td"></td>
                <td class="stmt-td stmt-td--num stmt-td--bold">{fmt(STARTING_BALANCE)}</td>
              </tr>

              {/* Transaction rows */}
              {My_Rows?.map(row => {
                const tx = row?.Cl_tx;
                if (!tx) return null;
                return (
                  <tr class="stmt-row">
                    <td class="stmt-td stmt-td--date">{tx.SERVICE_DATE ? moment(tx.SERVICE_DATE).format(DATE_DISPLAY) : '—'}</td>
                    <td class="stmt-td">{tx.DESCRIPTION || '—'}</td>
                    <td class="stmt-td stmt-td--doc">{row.DOC_NUMBER || '—'}</td>
                    <td class="stmt-td stmt-td--num">{tx.DEBIT ? fmt(tx.DEBIT) : '—'}</td>
                    <td class="stmt-td stmt-td--num">{tx.CREDIT ? fmt(tx.CREDIT) : '—'}</td>
                    <td class="stmt-td stmt-td--num">{fmt(row.RUNNING_BALANCE)}</td>
                  </tr>
                );
              })}

              {/* Closing balance */}
              <tr class="stmt-row stmt-row--balance">
                <td class="stmt-td" colSpan={3}>
                  Closing Balance — {moment(this.toDate).format(DATE_DISPLAY)}
                </td>
                <td class="stmt-td"></td>
                <td class="stmt-td"></td>
                <td class="stmt-td stmt-td--num stmt-td--bold">{fmt(ENDING_BALANCE)}</td>
              </tr>
            </tbody>
          </table>
        </div>
      </Host>
    );
  }
}
